### Board Class

```python
class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize board with pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece('black')
        for i in range(5, 8):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece('white')

    def display(self):
        # Display the board
        print("   a b c d e f g h")
        for i, row in enumerate(self.board):
            line = f"{8-i} "
            for piece in row:
                if piece is None:
                    line += ". "
                else:
                    line += str(piece) + " "
            print(line)

    def apply_move(self, start_pos, end_pos):
        # Apply a move to the board
        start_x, start_y = ord(start_pos[0]) - 97, int(start_pos[1])
        end_x, end_y = ord(end_pos[0]) - 97, int(end_pos[1])

        if self.board[start_x][start_y] is not None and (end_x, end_y) in self.get_moves(start_x, start_y):
            self.board[end_x][end_y] = self.board[start_x][start_y]
            self.board[start_x][start_y] = None
            # Promote piece if it reaches the other side
            if (self.board[end_x][end_y].owner == 'black' and end_x == 7) or \
               (self.board[end_x][end_y].owner == 'white' and end_x == 0):
                self.board[end_x][end_y].promote()
        else:
            print("Invalid move")

    def get_moves(self, x, y):
        # Placeholder for move logic
        moves = []
        piece = self.board[x][y]
        if piece is not None and piece.owner == 'black':
            moves.append((x-1, y+1))
            moves.append((x-1, y-1))
        elif piece is not None and piece.owner == 'white':
            moves.append((x+1, y+1))
            moves.append((x+1, y-1))
        return [(i, j) for i, j in moves if 0 <= i < 8 and 0 <= j < 8]
```

